58:             else if (callback instanceof DelegationTokenCredentialCallback) {
59:                 DelegationTokenCredentialCallback tokenCallback = (DelegationTokenCredentialCallback) callback;
60:                 tokenCallback.scramCredential(tokenCache.credential(saslMechanism, username));
61:                 tokenCallback.tokenOwner(tokenCache.owner(username));
62:                 TokenInformation tokenInfo = tokenCache.token(username);
