64:                     tokenCallback.tokenExpiryTimestamp(tokenInfo.expiryTimestamp());
65:             } else if (callback instanceof ScramCredentialCallback) {
66:                 ScramCredentialCallback sc = (ScramCredentialCallback) callback;
