34: /**
35:  * Default callback handler for Sasl servers. The callbacks required for all the SASL
36:  * mechanisms enabled in the server should be supported by this callback handler. See
37:  * <a href="https://docs.oracle.com/javase/8/docs/technotes/guides/security/sasl/sasl-refguide.html">Java SASL API</a>
38:  * for the list of SASL callback handlers required for each SASL mechanism.
39:  */
40: public class SaslServerCallbackHandler implements AuthenticateCallbackHandler {
41:     private static final Logger LOG = LoggerFactory.getLogger(SaslServerCallbackHandler.class);
42: 
43:     private String mechanism;
44: 
45:     @Override
46:     public void configure(Map<String, ?> configs, String mechanism, List<AppConfigurationEntry> jaasConfigEntries) {
47:         this.mechanism = mechanism;
48:     }
49: 
50:     @Override
51:     public void handle(Callback[] callbacks) throws UnsupportedCallbackException {
52:         for (Callback callback : callbacks) {
53:             if (callback instanceof RealmCallback)
54:                 handleRealmCallback((RealmCallback) callback);
55:             else if (callback instanceof AuthorizeCallback && mechanism.equals(SaslConfigs.GSSAPI_MECHANISM))
56:                 handleAuthorizeCallback((AuthorizeCallback) callback);
57:             else
58:                 throw new UnsupportedCallbackException(callback);
59:         }
60:     }
61: 
62:     private void handleRealmCallback(RealmCallback rc) {
63:         LOG.trace("Client supplied realm: {} ", rc.getDefaultText());
64:         rc.setText(rc.getDefaultText());
65:     }
66: 
67:     private void handleAuthorizeCallback(AuthorizeCallback ac) {
68:         String authenticationID = ac.getAuthenticationID();
69:         String authorizationID = ac.getAuthorizationID();
70:         LOG.info("Successfully authenticated client: authenticationID={}; authorizationID={}.",
71:                 authenticationID, authorizationID);
72:         ac.setAuthorized(true);
73:         ac.setAuthorizedID(authenticationID);
74:     }
75: 
76:     @Override
77:     public void close() {
78:     }
79: }
