29: /**
30:  * A size delimited Receive that consists of a 4 byte network-ordered size N followed by N bytes of content
31:  */
32: public class NetworkReceive implements Receive {
33: 
34:     public static final String UNKNOWN_SOURCE = "";
35:     public static final int UNLIMITED = -1;
36:     private static final Logger log = LoggerFactory.getLogger(NetworkReceive.class);
37:     private static final ByteBuffer EMPTY_BUFFER = ByteBuffer.allocate(0);
38: 
39:     private final String source;
40:     private final ByteBuffer size;
41:     private final int maxSize;
42:     private final MemoryPool memoryPool;
43:     private int requestedBufferSize = -1;
44:     private ByteBuffer buffer;
45: 
46: 
47:     public NetworkReceive(String source, ByteBuffer buffer) {
48:         this(UNLIMITED, source);
49:         this.buffer = buffer;
50:     }
51: 
52:     public NetworkReceive(String source) {
53:         this(UNLIMITED, source);
54:     }
55: 
56:     public NetworkReceive(int maxSize, String source) {
57:         this(maxSize, source, MemoryPool.NONE);
58:     }
59: 
60:     public NetworkReceive(int maxSize, String source, MemoryPool memoryPool) {
61:         this.source = source;
62:         this.size = ByteBuffer.allocate(4);
63:         this.buffer = null;
64:         this.maxSize = maxSize;
65:         this.memoryPool = memoryPool;
66:     }
67: 
68:     public NetworkReceive() {
69:         this(UNKNOWN_SOURCE);
70:     }
71: 
72:     @Override
73:     public String source() {
74:         return source;
75:     }
76: 
77:     @Override
78:     public boolean complete() {
79:         return !size.hasRemaining() && buffer != null && !buffer.hasRemaining();
80:     }
81: 
82:     public long readFrom(ScatteringByteChannel channel) throws IOException {
83:         int read = 0;
84:         if (size.hasRemaining()) {
85:             int bytesRead = channel.read(size);
86:             if (bytesRead < 0)
87:                 throw new EOFException();
88:             read += bytesRead;
89:             if (!size.hasRemaining()) {
90:                 size.rewind();
91:                 int receiveSize = size.getInt();
92:                 if (receiveSize < 0)
93:                     throw new InvalidReceiveException("Invalid receive (size = " + receiveSize + ")");
94:                 if (maxSize != UNLIMITED && receiveSize > maxSize)
95:                     throw new InvalidReceiveException("Invalid receive (size = " + receiveSize + " larger than " + maxSize + ")");
96:                 requestedBufferSize = receiveSize; // may be 0 for some payloads (SASL)
97:                 if (receiveSize == 0) {
98:                     buffer = EMPTY_BUFFER;
99:                 }
100:             }
101:         }
102:         if (buffer == null && requestedBufferSize != -1) { // we know the size we want but haven't been able to allocate it yet
103:             buffer = memoryPool.tryAllocate(requestedBufferSize);
104:             if (buffer == null)
105:                 log.trace("Broker low on memory - could not allocate buffer of size {} for source {}", requestedBufferSize, source);
106:         }
107:         if (buffer != null) {
108:             int bytesRead = channel.read(buffer);
109:             if (bytesRead < 0)
110:                 throw new EOFException();
111:             read += bytesRead;
112:         }
113: 
114:         return read;
115:     }
