117:     @Override
118:     public boolean requiredMemoryAmountKnown() {
119:         return requestedBufferSize != -1;
120:     }
121: 
122:     @Override
123:     public boolean memoryAllocated() {
124:         return buffer != null;
125:     }
126: 
127: 
128:     @Override
129:     public void close() throws IOException {
130:         if (buffer != null && buffer != EMPTY_BUFFER) {
131:             memoryPool.release(buffer);
132:             buffer = null;
133:         }
134:     }
